1	package util
2	
3	import "fmt"
4	
5	type EnumItem struct {
6		Key   string `json:"key"`   // 枚举key（如 "pending"）
7		Value string `json:"value"` // 枚举值（如 "排队中"）
8	}
9	
10	// EnumProvider is an interface for enum providers
11	type EnumProvider interface {
12		GetEnum() []EnumItem
13	}
14	
15	// EnumRegistry 枚举注册表
16	type EnumRegistry struct {
17		providers map[string]EnumProvider
18	}
19	
20	// NewEnumRegistry 创建新的枚举注册表
21	func NewEnumRegistry() *EnumRegistry {
22		return &EnumRegistry{
23			providers: make(map[string]EnumProvider),
24		}
25	}
26	
27	// Register 注册枚举提供者
28	func (r *EnumRegistry) Register(enumType string, provider EnumProvider) {
29		r.providers[enumType] = provider
30	}
31	
32	// GetEnum 获取枚举值
33	func (r *EnumRegistry) GetEnum(enumType string) (interface{}, error) {
34		if provider, exists := r.providers[enumType]; exists {
35			return provider.GetEnum(), nil
36		}
37		return nil, fmt.Errorf("enum type '%s' not found", enumType)
38	}
39	
40	// GetAvailableTypes 获取可用的枚举类型
41	func (r *EnumRegistry) GetAvailableTypes() []string {
42		types := make([]string, 0, len(r.providers))
43		for t := range r.providers {
44			types = append(types, t)
45		}
46		return types
47	}
